/**
 * Update the discount rate associated with a given royalty tier if it exists
 * @param program - GalacticMarketplace Program
 * @param updateAuthorityAccount - the authority of the market
 * @param registeredCurrency - a valid registered currency
 * @param stakeAmount - the staked amount in the token's base units
 * @param discount - the new discount amount (Discount of '1_000_000' == 100%)
 * @returns InstructionReturn
 */
export function updateRoyaltyTier(
  program: GalacticMarketplaceIDLProgram,
  updateAuthorityAccount: AsyncSigner,
  registeredCurrency:
    | { registeredCurrency: RegisteredCurrency }
    | { key: PublicKey },
  stakeAmount: number,
  discount: number,
): InstructionReturn {
  const registeredCurrencyAddress =
    'key' in registeredCurrency
      ? registeredCurrency.key
      : registeredCurrency.registeredCurrency.key;
  return async () => ({
    instruction: await program.methods
      .updateRoyaltyTier(new BN(stakeAmount), new BN(discount))
      .accountsStrict({
        updateAuthorityAccount: updateAuthorityAccount.publicKey(),
        marketVarsAccount: MarketVars.findAddress(program)[0],
        registeredCurrency: registeredCurrencyAddress,
      })
      .instruction(),
    signers: [updateAuthorityAccount],
  });
}
